var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"마지막 스테이지……. 이것만 클리어하면…… 이번 테스트는 끝.","JPN":"最後のステージ……これさえクリアすれば……今回のテストは終わり。","ENG":"The last stage... We clear this... this test is over.","TWN":"最後一關……過關後……測試就結束了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"벌써 여까지 왔네. 니들이랑 하니까 금방 왔다.","JPN":"もうここまで来たなあ。あんたたちとやるとすぐ着いたわ。","ENG":"We've already come this far, eh? Didn't take that long playin' with y'all.","TWN":"這麼快就要結束啦？和你們在一起時間總是過得特別快。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"전부 기록하고 있었어……. 테스트.","JPN":"全部記録していた……テスト。","ENG":"Everything is being recorded... The test.","TWN":"全都有記錄下來……測試過程。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"나중에……. 공유해줄게.","JPN":"後で……共有する。","ENG":"Later… I'll... share it with you.","TWN":"之後……分享給你們。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하하, 우리 보라는 역시 일도 센스 있게 참 잘해.","JPN":"はは、シホは仕事のセンスも抜群やな。","ENG":"Ha ha, I knew Bora always had a good work ethic and wits.","TWN":"哈哈，我們寶拉做事真的很可靠呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"내가 뭘…….","JPN":"別に……","ENG":"Me...?","TWN":"我有做什麼嗎……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"자 그럼 준비됐제? 후딱 끝내고 나가보자.","JPN":"さて、準備はできた？　すぐ終わらせて出よ。","ENG":"Now, y'all ready? Let's get this over with.","TWN":"大家都準備好了嗎？速戰速決吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"잠깐만 얘들아, 시작하기 전에 할 말이 있어.","JPN":"ちょっと、二人とも。始める前に話があるの。","ENG":"Hold on. I need to say something before we start.","TWN":"先等一下，我有話要跟大家說。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"오늘……. 둘이 와줘서 정말 고마워.","JPN":"今日は……来てくれて本当にありがとう。","ENG":"I want to say... thank you to the both of you for coming.","TWN":"今天……很謝謝你們來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"오늘 정말 즐거웠어. 마치 <color=#ffd34c>동창회</color>에 온 것만 같아.","JPN":"今日は本当に楽しかったわ。まるで<color=#ffd34c>同窓会</color>に来たみたい。","ENG":"I had a lot of fun today. This felt like the <color=#ffd34c>reunion</color>.","TWN":"我今天真的很開心，好像來參加<color=#ffd34c>同學會</color>一樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"다음엔 꼭 직접 만나자. 아니면 아카데미에 찾아와줘도 좋고.","JPN":"今度は絶対直接会いましょう。それかアカデミーに来てくれてもいいわ。","ENG":"Let's meet in person next time. Or you could drop by the Academy.","TWN":"希望下次可以親眼見到大家，也歡迎你們來學院找我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"……물론.","JPN":"……もちろん。","ENG":"...Sure.","TWN":"……那當然。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"마, 누가 들으면 영원히 헤어지는 줄 알긋다!","JPN":"ちょっと、他の人が聞いたら永遠の別れだと勘違いされるで！","ENG":"Hey, that sounds like we're never gonna see each other again!","TWN":"真是的，你說的好像我們現在是要永遠分開一樣！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내가 옛날에 얘기했제? 우린 영원히 함께고, 앞으로도 바뀌지 않을 거라고.","JPN":"昔ウチが言ったやん？　ウチらはずっと一緒で、これからも変わらへんって。","ENG":"Didn't I say it a long time ago? We're gonna be together forever and nothin's gonna change that.","TWN":"我以前不是說過？我們要永遠在一起，以後也不會改變。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그리고 다인아, 방금 동창회를 한 것만 같다고 했제?","JPN":"それにタエ、さっき同窓会に来たみたいって言うたやろ？","ENG":"And Dain, you said that this felt like a reunion, right?","TWN":"還有，妲茵，你剛說到同學會對嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하지만 이건 아직 동창회라 할 수 없다.","JPN":"これはまだ同窓会とは言えへんわ。","ENG":"But this can't be called that just yet.","TWN":"這還不能說是同學會。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……뭔 말인지 알제?","JPN":"……どういう意味なのかわかるやろ？","ENG":"...Ya know what I mean, right?","TWN":"……你懂我意思唄？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"후훗, 맞아.","JPN":"ふふっ、そうね。","ENG":"Ha ha. You're right.","TWN":"呵呵，我懂。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"……당연하지.","JPN":"……もちろん。","ENG":"…Of course.","TWN":"……沒錯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_BOX","text":{"KOREA":"한 명이 빠졌다. 한 명이.","JPN":"一人足りへん、一人が。","ENG":"We're missin' just one person.","TWN":"還少一個。"},"stage":{"bg":"BLACK","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_BOX","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_PROMISE_NULL_BOX","text":{"KOREA":"그날……. 약속했다 아이가.","JPN":"あの日……約束したやんか。","ENG":"That day... we made a promise.","TWN":"那天……我們說好的。"},"stage":{"bg":"BLACK","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_BOX","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_PROMISE_NULL_BOX","text":{"KOREA":"<color=#ffd34c>철수</color>…… 다시 만나러 가기로.","JPN":"<color=#ffd34c>ジロウ</color>……また会いに行くって。","ENG":"To go see <color=#ffd34c>Chulsoo</color>... again.","TWN":"要再去看……<color=#ffd34c>哲洙</color>。"},"stage":{"bg":"BLACK","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_BOX","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"……잊었을 리 없잖아.","JPN":"……忘れるはずがないわ。","ENG":"...I haven't forgotten.","TWN":"……我當然沒忘。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"잊어본 적 없어……. 단 하루도.","JPN":"忘れたことはない……一日も。","ENG":"Not even... for a single day.","TWN":"從沒……忘記過。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"반드시 지키는기다. 그때 한 약속.","JPN":"必ず守る。あの時の約束。","ENG":"We're gonna keep that promise we made that day.","TWN":"一定要遵守約定。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"……학생들이 기다리고 있어. 어서 진행하자.","JPN":"……生徒たちが待ってる。早く進めましょう。","ENG":"...The students are waiting. Let's move on.","TWN":"……學生們都在等著呢，快開始吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"좋아……. 바로 출격시킬게.","JPN":"いいよ……すぐ出撃させる。","ENG":"All right... I'll send you out right now.","TWN":"好……立刻出擊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};